import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limiting the input length to prevent buffer overflow
        byte[] buffer = new byte[10];
        byte[] userInputBytes = input.getBytes();

        if (userInputBytes.length > buffer.length) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
            return;
        }

        // Copy user input into the buffer array
        System.arraycopy(userInputBytes, 0, buffer, 0, userInputBytes.length);

        System.out.println("Secure buffer handling completed.");
    }
}

